import pytest

def test_deep_get_happy_path():
    """Test basic nested dictionary access with dot notation."""
    data = {
        'a': {
            'b': {
                'c': 42
            }
        }
    }
    assert deep_get(data, 'a.b.c') == 42
    assert deep_get(data, 'a.b') == {'c': 42}
    assert deep_get(data, 'a') == {'b': {'c': 42}}

def test_deep_get_with_default():
    """Test returning default value when key doesn't exist."""
    data = {'a': {'b': 1}}
    assert deep_get(data, 'a.c', default='not found') == 'not found'
    assert deep_get(data, 'x.y.z') is None
    assert deep_get(data, 'a.b.c.d', default=0) == 0

def test_deep_get_empty_keys():
    """Test with empty keys string."""
    data = {'a': 1}
    assert deep_get(data, '') == data
    assert deep_get(data, '', default='default') == data

def test_deep_get_single_key():
    """Test with single key (no dots)."""
    data = {'a': 1, 'b': 2}
    assert deep_get(data, 'a') == 1
    assert deep_get(data, 'b') == 2
    assert deep_get(data, 'c', default='missing') == 'missing'

def test_deep_get_non_dict_intermediate():
    """Test when intermediate value is not a dict."""
    data = {
        'a': {
            'b': 'not a dict',
            'c': {'d': 3}
        }
    }
    assert deep_get(data, 'a.b.x') is None
    assert deep_get(data, 'a.c.d') == 3
    assert deep_get(data, 'a.b.x.y', default='error') == 'error'

def test_deep_get_none_values():
    """Test when dictionary contains None values."""
    data = {
        'a': None,
        'b': {'c': None}
    }
    assert deep_get(data, 'a') is None
    assert deep_get(data, 'b.c') is None
    assert deep_get(data, 'a.x', default='default') == 'default'

def test_deep_get_empty_dict():
    """Test with empty dictionary."""
    data = {}
    assert deep_get(data, 'a.b.c') is None
    assert deep_get(data, 'a', default=0) == 0

def test_deep_get_non_dict_input():
    """Test when input is not a dictionary."""
    assert deep_get(None, 'a.b') is None
    assert deep_get([1, 2, 3], '0.1', default='not dict') == 'not dict'
    assert deep_get("string", 'a.b') is None
    assert deep_get(123, 'a', default='number') == 'number'

def test_deep_get_special_characters_in_keys():
    """Test with keys containing special characters."""
    data = {
        'a.b': {'c.d': 'value'},
        'x': {'y:z': 'another'}
    }
    assert deep_get(data, 'a.b.c.d') == 'value'
    assert deep_get(data, 'x.y:z') == 'another'
    assert deep_get(data, 'a\\.b.c\\.d') is None  # Escaped dots are treated literally

def test_deep_get_whitespace_in_keys():
    """Test with keys containing whitespace."""
    data = {
        'a b': {'c d': 'value'},
        'x': {' y ': 'another'}
    }
    assert deep_get(data, 'a b.c d') == 'value'
    assert deep_get(data, 'x. y ') == 'another'

def test_deep_get_deeply_nested():
    """Test with deeply nested structure."""
    data = {
        'a': {
            'b': {
                'c': {
                    'd': {
                        'e': 'deep value'
                    }
                }
            }
        }
    }
    assert deep_get(data, 'a.b.c.d.e') == 'deep value'
    assert deep_get(data, 'a.b.c.d.e.f', default='too deep') == 'too deep'
